def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1.2)
                    mod = np.tanh(np.sin(ratio * b / (a + 0.9)) * val) * 2.3
                    priority += mod
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 1.8
            for u in range(1, 5):
                if (i + u) % 2 == 0:
                    priority += np.cos(ratio * i * u * 0.7) * 1.4
                else:
                    priority -= np.sin(ratio * u * 0.9) * 1.1
        elif 5 < ratio <= 8:
            for c in range(2, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 4):
                    term = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.75)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 13 - np.tanh(ratio - 5) * 2.8
            if bin_cap < item * 1.3:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 3.5
            else:
                priority -= np.cos(18 * ratio) * 2.1
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 1.6) * np.sin(e * ratio * 1.1)
            priority = (s * np.cos(6 * ratio)) - np.log(ratio) * 7 + np.tanh(3.5 * (5 - ratio)) * 1.7
            for f in range(1, 6):
                priority += np.cos(f * ratio * i) * ((ratio - 1.9) ** f) / (f + 0.5)
        elif 0.7 <= ratio < 2:
            s = 0
            for g in range(1, 12):
                s += ((2 - ratio) ** g) / (g ** 2 + 1) * np.cos(g * ratio * 0.9)
            if bin_cap > item * 1.15:
                penalty = np.log(item / (bin_cap + 0.7)) * 3.8
            else:
                penalty = np.sin(22 * ratio) * 2.2
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for h in range(1, 7):
                priority += np.sin(h * ratio * i * 0.95) * ((ratio - 0.7) ** h) / (h + 0.3)
        elif 0.3 <= ratio < 0.7:
            s = 0
            for j in range(1, 18):
                s += ((0.7 - ratio) ** j) / (j * 3.7)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2.7) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2.1) + 1.7)
            for k in range(1, 8):
                priority += ((0.7 - ratio) ** k) * np.sin(k * item * 1.4) * 0.9
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * 2
        elif 0.1 <= ratio < 0.3:
            s = 0
            for l in range(1, 14):
                s += ((0.3 - ratio) ** l) / (l * 2.5) * np.cos(l * ratio * 3)
            priority = s + 2 / (bin_cap + 2.5)
            if int(item * 1.5) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 1.5) * 2.5
            for m in range(1, 9):
                priority += ((0.3 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.05)
        else:
            s = 0
            for n in range(1, 13):
                s += ((0.1 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.1)
            priority = s + 3 / (bin_cap + 3.5)
            if int(item * 0.8) % 4 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 4.7
            else:
                priority -= np.exp(-ratio * 2.5) * 3.8
            for o in range(1, 10):
                priority += ((0.1 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.3
            for p in range(1, 3):
                priority += np.sin(p * ratio * i * 1.2) * 0.7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.2
            for q in range(1, 5):
                if (i + q) % 4 == 0:
                    priority += np.cos(ratio * (i + q)) * 0.4
                else:
                    priority -= np.sin(ratio * (i + q)) * 0.4
        for r in range(1, 6):
            if (i * r) % 5 == 0:
                priority += np.sin(ratio * i * r * 1.3) * 0.8
            else:
                priority -= np.cos(ratio * i * r * 1.3) * 0.8
        priorities[i] = priority
    return priorities
